const cleanedTasks = [];
let totalTasks = 0;
const ownerCounts = {};
const statusCounts = {};
let overdueCount = 0;
let completedTasks = 0;

// Grab the bundled array of tasks
const allTasks = $input.first().json.compiled_tasks || $input.all().map(item => item.json);

for (const task of allTasks) {
  totalTasks++;

  // 1. Status Aggregation
  const statusName = task.status?.status || "unmapped";
  const formattedStatus = statusName.charAt(0).toUpperCase() + statusName.slice(1);
  statusCounts[formattedStatus] = (statusCounts[formattedStatus] || 0) + 1;

  if (statusName.toLowerCase() === 'done' || statusName.toLowerCase() === 'closed') {
      completedTasks++;
  }

  // 2. Owner Aggregation
  const assignees = task.assignees || [];
  const taskOwner = assignees.length > 0 ? assignees.map(a => a.username).join(', ') : "Unassigned";
  ownerCounts[taskOwner] = (ownerCounts[taskOwner] || 0) + 1;

  // 3. Overdue Check
  const dueDate = task.due_date;
  if (dueDate && parseInt(dueDate) < Date.now() && (statusName.toLowerCase() !== 'done' && statusName.toLowerCase() !== 'closed')) {
      overdueCount++;
  }

  // 4. Thread extraction (Updated to map the nested comments array)
  let discussionThread = "No discussion yet.";
  const commentsArray = task.comments || []; // Targets the nested array

  if (commentsArray.length > 0) {
      discussionThread = commentsArray.map(c => {
          const author = c.user?.username || "Unknown";
          const dateStr = new Date(parseInt(c.date)).toLocaleString('en-US', { timeZone: 'Asia/Manila', hour12: true });
          const cleanText = (c.comment_text || "").replace(/\n{2,}/g, '\n').trim();
          return `[${dateStr}] ${author}: ${cleanText}`;
      }).join('\n\n');
  }

  // Push everything together
  cleanedTasks.push({
      task_id: task.id || "N/A",
      task_name: task.name || "Unnamed Task",
      task_owner: taskOwner,
      status: formattedStatus,
      discussion_thread: discussionThread
  });
}

const completionRate = totalTasks === 0 ? 0 : Math.round((completedTasks / totalTasks) * 100);

return [{
  json: {
    dashboard_metrics: {
      total_tasks: totalTasks,
      completion_rate: completionRate,
      overdue_tasks: overdueCount,
      tasks_by_owner: ownerCounts,
      tasks_by_status: statusCounts
    },
    sprint_data: cleanedTasks
  }
}];

// 1. Fetch the global metrics directly from the Output Cleaner node
const metricsItem = $items("Output Cleaner")[0];
const metrics = metricsItem ? metricsItem.json.dashboard_metrics : {};

const totalTasks = metrics.total_tasks || 0;
const completionRate = metrics.completion_rate || 0;
const overdueTasks = metrics.overdue_tasks || 0;
const ownerCounts = metrics.tasks_by_owner || {};
const statusCounts = metrics.tasks_by_status || {};

// 2. Generate the QuickChart.io Pie Chart URL for Global Status
const chartLabels = Object.keys(statusCounts);
const chartData = Object.values(statusCounts);

const chartConfig = {
  type: 'outlabeledPie',
  data: {
    labels: chartLabels,
    datasets: [{
        backgroundColor: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#64748b'],
        data: chartData
    }]
  },
  options: {
    plugins: {
      legend: { display: false },
      outlabels: { text: '%l: %v', color: 'white', stretch: 35, font: { minSize: 12 } }
    }
  }
};
const encodedChartUrl = `https://quickchart.io/chart?w=500&h=250&c=${encodeURIComponent(JSON.stringify(chartConfig))}`;

// 3. Build the "Global Workload" HTML List
let ownerHtmlList = '<ul style="list-style-type: none; padding: 0; margin: 0;">';
// Sort owners by task count (highest first)
const sortedOwners = Object.entries(ownerCounts).sort((a, b) => b[1] - a[1]);
for (const [owner, count] of sortedOwners) {
    ownerHtmlList += `<li style="padding: 8px 0; border-bottom: 1px solid #f1f5f9; color: #475569; font-size: 15px;">
        <strong>${owner}</strong>: ${count} task(s)
    </li>`;
}
ownerHtmlList += '</ul>';

// 4. Build the Top Executive Stat Cards
const statCards = `
  <div style="margin-bottom: 30px; width: 100%;">
    <table width="100%" cellpadding="0" cellspacing="0" border="0">
      <tr>
        <td align="center" width="33%" style="padding: 0 5px;">
          <div style="background: #f8fafc; padding: 15px 10px; border-radius: 8px; border: 1px solid #e2e8f0;">
             <div style="font-size: 24px; font-weight: bold; color: #0f172a;">${totalTasks}</div>
             <div style="font-size: 11px; color: #64748b; text-transform: uppercase; margin-top: 5px;">Total Active Tasks</div>
          </div>
        </td>
        <td align="center" width="33%" style="padding: 0 5px;">
          <div style="background: #f0fdf4; padding: 15px 10px; border-radius: 8px; border: 1px solid #bbf7d0;">
             <div style="font-size: 24px; font-weight: bold; color: #166534;">${completionRate}%</div>
             <div style="font-size: 11px; color: #15803d; text-transform: uppercase; margin-top: 5px;">Global Completion</div>
          </div>
        </td>
        <td align="center" width="33%" style="padding: 0 5px;">
          <div style="background: #fef2f2; padding: 15px 10px; border-radius: 8px; border: 1px solid #fecaca;">
             <div style="font-size: 24px; font-weight: bold; color: #991b1b;">${overdueTasks}</div>
             <div style="font-size: 11px; color: #b91c1c; text-transform: uppercase; margin-top: 5px;">Tasks Overdue</div>
          </div>
        </td>
      </tr>
    </table>
  </div>
`;

// 5. Construct the Visual Dashboard Section
const dashboardSection = `
    ${statCards}
    <div style="margin-bottom: 40px;">
        <h2 style="color: #1e293b; font-size: 20px; border-bottom: 2px solid #3b82f6; padding-bottom: 8px; margin-bottom: 15px;">Global Sprint Distribution</h2>
        <div style="text-align: center; margin-bottom: 25px;">
            <img src="${encodedChartUrl}" alt="Task Status Pie Chart" style="max-width: 100%; height: auto;" />
        </div>
        <h2 style="color: #1e293b; font-size: 20px; border-bottom: 2px solid #3b82f6; padding-bottom: 8px; margin-bottom: 15px;">Team Workload</h2>
        ${ownerHtmlList}
    </div>
    <hr style="border: 0; height: 2px; background: #e2e8f0; margin: 30px 0;" />
`;

// 6. Process the AI Report Text (from this node's input)
let html = $input.first().json.output || "";

// Format the Markdown AI text into clean HTML
html = html.replace(/^(\*\*.*?\*\*)$/gm, '<h3 style="color: #334155; font-size: 18px; margin-top: 25px; margin-bottom: 10px;">$1</h3>');
html = html.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
html = html.replace(/`(.*?)`/g, '<code style="background-color: #f1f5f9; padding: 2px 4px; border-radius: 4px; color: #e11d48; font-size: 14px;">$1</code>');
html = html.replace(/^---$/gm, '<hr style="border: 0; height: 2px; background: #e2e8f0; margin: 30px 0;" />');
html = html.replace(/^##\s+(.*)/gm, '<h2 style="color: #1e293b; font-size: 22px; margin-top: 30px; margin-bottom: 15px; border-bottom: 2px solid #3b82f6; padding-bottom: 8px;">$1</h2>');
html = html.replace(/^\*\s+(.*)/gm, '<li style="margin-bottom: 10px;">$1</li>');
html = html.replace(/(<li.*?>.*?<\/li>\n?)+/g, match => `\n<ul style="margin-bottom: 20px; padding-left: 20px;">\n${match}</ul>\n`);

// Catch any unformatted paragraphs (like the Executive Summary) and wrap them
html = html.replace(/^(?!<)(.+)$/gm, '<p style="margin-bottom: 15px;">$1</p>');

// Combine Dashboard + AI Report with global font styling
const finalHtml = `
  <div style="font-family: Arial, sans-serif; color: #475569; font-size: 15px; line-height: 1.6; max-width: 750px; margin: 0 auto; padding: 30px; background-color: #ffffff; border: 1px solid #e2e8f0; border-radius: 8px;">
    <h1 style="text-align: center; color: #0f172a; font-size: 28px; line-height: 1.2; margin-bottom: 30px;">Executive Operations Report</h1>
    ${dashboardSection}
    ${html}
  </div>
`;

return [{
  json: {
    html_report: finalHtml
  }
}];

// 1. Paste your ClickUp API token here
const CLICKUP_API_TOKEN = 'pk_95098109_CKRN4NLD5ZHQSPTELI13QRJE4M63000I';

const openBugs = [];
const tasks = $input.all().map(item => item.json);

async function getOpenBugActivities() {
    for (const task of tasks) {

        // 1. CHECK STATUS: If it's closed/complete/done, completely ignore it.
        const status = task.status?.status?.toLowerCase() || "";
        if (['closed', 'complete', 'done'].includes(status)) {
            continue; 
        }

        // 2. FETCH COMMENTS: Grab the activities for this specific open bug
        let thread = "No activities yet.";

        try {
            const response = await this.helpers.httpRequest({
                method: 'GET',
                url: `https://api.clickup.com/api/v2/task/${task.id}/comment`,
                headers: {
                    'Authorization': CLICKUP_API_TOKEN,
                    'Content-Type': 'application/json'
                },
                json: true
            });

            if (response.comments && response.comments.length > 0) {
                thread = response.comments.map(c => {
                    const author = c.user?.username || "Unknown";
                    const dateStr = new Date(parseInt(c.date, 10)).toLocaleString('en-US', { timeZone: 'Asia/Manila' });
                    const cleanText = (c.comment_text || "").replace(/\n{2,}/g, '\n').trim();
                    return `[${dateStr}] ${author}: ${cleanText}`;
                }).join('\n\n');
            }
        } catch (error) {
            thread = "Error fetching activities.";
        }

        // 3. OUTPUT: Push exactly what you want to the final list
        openBugs.push({
            json: {
                task_id: task.id,
                task_name: task.name,
                status: task.status?.status,
                activities: thread
            }
        });
    }

    // Return the clean list of Open Bugs and their activities
    return openBugs;
}

return await getOpenBugActivities();
